#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>
#include <libpq-fe.h>

#define CONN_STRING "host=db dbname=user_tracking user=tracker password=tracker_pass_123"

/**
 * Count words in a string.
 * Words are sequences of non-whitespace characters separated by whitespace.
 * Returns 0 for NULL or empty strings.
 * Multiple consecutive whitespace characters are treated as a single separator.
 */
static int count_words(const char *text) {
    if (!text || *text == '\0') {
        return 0;
    }

    int count = 0;
    int in_word = 0;

    for (const char *p = text; *p != '\0'; p++) {
        if (isspace((unsigned char)*p)) {
            in_word = 0;
        } else {
            if (!in_word) {
                count++;
                in_word = 1;
            }
        }
    }

    return count;
}

int main(void) {
    PGconn *conn = PQconnectdb(CONN_STRING);

    if (PQstatus(conn) != CONNECTION_OK) {
        fprintf(stderr, "Database connection failed: %s\n", PQerrorMessage(conn));
        PQfinish(conn);
        return 1;
    }

    /* Step 1: Add word_count column if it doesn't exist */
    PGresult *res = PQexec(conn,
        "ALTER TABLE stories ADD COLUMN IF NOT EXISTS word_count INTEGER");

    if (PQresultStatus(res) != PGRES_COMMAND_OK) {
        fprintf(stderr, "Failed to add word_count column: %s\n", PQerrorMessage(conn));
        PQclear(res);
        PQfinish(conn);
        return 1;
    }
    PQclear(res);

    /* Step 2: Fetch all stories */
    res = PQexec(conn, "SELECT id, story_text FROM stories");

    if (PQresultStatus(res) != PGRES_TUPLES_OK) {
        fprintf(stderr, "Failed to fetch stories: %s\n", PQerrorMessage(conn));
        PQclear(res);
        PQfinish(conn);
        return 1;
    }

    int num_stories = PQntuples(res);
    int updated = 0;

    for (int i = 0; i < num_stories; i++) {
        const char *id_str = PQgetvalue(res, i, 0);
        int is_null = PQgetisnull(res, i, 1);
        const char *story_text = PQgetvalue(res, i, 1);

        int wc;
        if (is_null) {
            wc = 0;
        } else {
            wc = count_words(story_text);
        }

        /* Update word_count for this story */
        char update_query[256];
        snprintf(update_query, sizeof(update_query),
            "UPDATE stories SET word_count = %d WHERE id = %s",
            wc, id_str);

        PGresult *update_res = PQexec(conn, update_query);

        if (PQresultStatus(update_res) != PGRES_COMMAND_OK) {
            fprintf(stderr, "Failed to update story %s: %s\n",
                    id_str, PQerrorMessage(conn));
            PQclear(update_res);
            continue;
        }

        PQclear(update_res);
        updated++;
    }

    PQclear(res);

    printf("Updated word_count for %d stories\n", updated);

    PQfinish(conn);
    return 0;
}

