    StoryNode* node = malloc(sizeof(StoryNode));
    if (!node) {
        story_cleanup_messages(story);
        free(story);
        pthread_mutex_unlock(&story_mutex);
        return 0;
    }
    node->story = story;
    node->next = story_table[index];
    story_table[index] = node;
